#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <cuda_runtime.h>

__inline__ uint64_t rdtsc()
{
    uint32_t lo, hi;
    __asm__ __volatile__("rdtsc" : "=a"(lo), "=d"(hi));
    return ((uint64_t)hi << 32) | lo;
}

unsigned long long start_cycles;
#define startCycle() (start_cycles = rdtsc())
#define stopCycle(cycles) (cycles = rdtsc() - start_cycles)

#define pin_stats_reset()   startCycle()
#define pin_stats_pause(cycles)   stopCycle(cycles)
#define pin_stats_dump(cycles)    printf("timer: %Lu\n", cycles)

#define BENCH_PRINT

int rows, cols;
int* data;
int** wall;
int* result;
#define M_SEED 9

static inline void cuda_check(cudaError_t err, const char* msg)
{
    if (err != cudaSuccess) {
        fprintf(stderr, "error: %s: %s\n", msg, cudaGetErrorString(err));
        exit(1);
    }
}

void run(int argc, char** argv);

void init(int argc, char** argv)
{
    if (argc == 3) {
        cols = atoi(argv[1]);
        rows = atoi(argv[2]);
    } else {
        printf("Usage: pathfiner width num_of_steps\n");
        exit(0);
    }

    data = new int[rows * cols];
    wall = new int*[rows];
    for (int n = 0; n < rows; n++)
        wall[n] = data + cols * n;
    result = new int[cols];

    int seed = M_SEED;
    srand(seed);

    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            wall[i][j] = rand() % 10;
        }
    }
    for (int j = 0; j < cols; j++)
        result[j] = wall[0][j];

#ifdef BENCH_PRINT
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            printf("%d ", wall[i][j]);
        }
        printf("\n");
    }
#endif
}

void fatal(char *s)
{
    fprintf(stderr, "error: %s\n", s);
}

#define IN_RANGE(x, min, max)   ((x) >= (min) && (x) <= (max))
#define CLAMP_RANGE(x, min, max) x = (x < (min)) ? (min) : ((x > (max)) ? (max) : (x))
#define MIN(a, b) ((a) <= (b) ? (a) : (b))

__global__ void pathfinder_kernel(const int* wall_data, const int* src, int* dst, int cols, int row_idx)
{
    int n = blockIdx.x * blockDim.x + threadIdx.x;
    if (n < cols) {
        int minv = src[n];
        if (n > 0)
            minv = min(minv, src[n - 1]);
        if (n < cols - 1)
            minv = min(minv, src[n + 1]);
        dst[n] = wall_data[row_idx * cols + n] + minv;
    }
}

int main(int argc, char** argv)
{
    run(argc, argv);
    return EXIT_SUCCESS;
}

void run(int argc, char** argv)
{
    init(argc, argv);

    unsigned long long cycles;

    int *src, *dst, *temp;
    int *d_src, *d_dst, *d_temp, *d_wall;

    dst = result;
    src = new int[cols];

    cuda_check(cudaMalloc((void**)&d_wall, (size_t)rows * (size_t)cols * sizeof(int)), "cudaMalloc d_wall");
    cuda_check(cudaMalloc((void**)&d_src, (size_t)cols * sizeof(int)), "cudaMalloc d_src");
    cuda_check(cudaMalloc((void**)&d_dst, (size_t)cols * sizeof(int)), "cudaMalloc d_dst");

    cuda_check(cudaMemcpy(d_wall, data, (size_t)rows * (size_t)cols * sizeof(int), cudaMemcpyHostToDevice), "cudaMemcpy wall");
    cuda_check(cudaMemcpy(d_dst, dst, (size_t)cols * sizeof(int), cudaMemcpyHostToDevice), "cudaMemcpy initial result");

    int threads = 256;
    int blocks = (cols + threads - 1) / threads;

    pin_stats_reset();
    for (int t = 0; t < rows - 1; t++) {
        temp = src;
        src = dst;
        dst = temp;

        d_temp = d_src;
        d_src = d_dst;
        d_dst = d_temp;

        pathfinder_kernel<<<blocks, threads>>>(d_wall, d_src, d_dst, cols, t + 1);
        cuda_check(cudaGetLastError(), "kernel launch");
    }
    cuda_check(cudaDeviceSynchronize(), "cudaDeviceSynchronize");
    pin_stats_pause(cycles);
    pin_stats_dump(cycles);

    cuda_check(cudaMemcpy(dst, d_dst, (size_t)cols * sizeof(int), cudaMemcpyDeviceToHost), "cudaMemcpy result back");

#ifdef BENCH_PRINT
    for (int i = 0; i < cols; i++)
        printf("%d ", data[i]);
    printf("\n");

    for (int i = 0; i < cols; i++)
        printf("%d ", dst[i]);
    printf("\n");
#endif

    cudaFree(d_wall);
    cudaFree(d_src);
    cudaFree(d_dst);

    delete [] data;
    delete [] wall;
    delete [] dst;
    delete [] src;
}
